function max_activities(starts, ends) {
    const n = starts.length;
    const idx = Array.from({length:n}, (_,i)=>i).sort((a,b)=>ends[a]-ends[b]);
    let count = 0, lastEnd = -Infinity;
    for (const i of idx) { if (starts[i] >= lastEnd) { count++; lastEnd = ends[i]; } }
    return count;
}

function closest_pair_sq_dist(points) {
    let best = Infinity;
    for (let i=0;i<points.length;i++) for (let j=i+1;j<points.length;j++) {
        const dx = points[i][0]-points[j][0], dy = points[i][1]-points[j][1];
        const d = dx*dx+dy*dy;
        if (d < best) best = d;
    }
    return best;
}

function count_occurrences(nums, target) {
    function lb(t) { let lo=0,hi=nums.length; while(lo<hi){const mid=(lo+hi)>>1; if(nums[mid]<t)lo=mid+1;else hi=mid;} return lo; }
    const first=lb(target), last=lb(target+1);
    return (last-first);
}

function egg_drop(eggs, floors) {
    if (floors === 0) return 0;
    const dp = new Array(eggs+1).fill(0);
    let moves = 0;
    while (dp[eggs] < floors) {
        moves++;
        for (let k=eggs;k>=1;k--) dp[k] = dp[k] + dp[k-1] + 1;
    }
    return moves;
}

