function find_target_sum_ways(nums, target) {
    const total = nums.reduce((a,b)=>a+b,0);
    if (Math.abs(target)>total) return 0;
    const offset=total; const size=2*total+1;
    let dp=new Array(size).fill(0); dp[offset]=1;
    for (const x of nums) {
        const ndp=new Array(size).fill(0);
        for (let s=0;s<size;s++) {
            if (dp[s]===0) continue;
            if (s+x<size) ndp[s+x]+=dp[s];
            if (s-x>=0) ndp[s-x]+=dp[s];
        }
        dp=ndp;
    }
    const idx=target+offset;
    return (idx>=0 && idx<size ? dp[idx] : 0);
}

function count_pairs(nums, target) {
    const freq={}; let count=0;
    for (const x of nums) {
        const need=target-x;
        if (freq[need]) count+=freq[need];
        freq[x]=(freq[x]||0)+1;
    }
    return count;
}

function word_wrap(lengths, width) {
    const n=lengths.length; const INF=1e15;
    const dp=new Array(n+1).fill(INF); dp[n]=0;
    for (let i=n-1;i>=0;i--) {
        let lineLen=-1;
        for (let j=i;j<n;j++) {
            lineLen += lengths[j]+1;
            if (lineLen>width) break;
            const cost = (j===n-1) ? 0 : (width-lineLen)*(width-lineLen)*(width-lineLen);
            if (dp[j+1]+cost<dp[i]) dp[i]=dp[j+1]+cost;
        }
    }
    return dp[0];
}
